import{c as t,Q as o,j as d,m as a}from"./chunks/framework.iD28w_5a.js";const p=JSON.parse('{"title":"ext2 文件系统","description":"","frontmatter":{},"headers":[],"relativePath":"document/kernel/fs/ext2.md","filePath":"document/kernel/fs/ext2.md","lastUpdated":1777209094000}'),i={name:"document/kernel/fs/ext2.md"};function c(l,e,r,n,s,h){return o(),d("div",null,[...e[0]||(e[0]=[a('<h1 id="ext2-文件系统" tabindex="-1">ext2 文件系统 <a class="header-anchor" href="#ext2-文件系统" aria-label="Permalink to &quot;ext2 文件系统&quot;">​</a></h1><blockquote><p>里程碑: <code>028_fs_ext2</code> <code>028b_fs_ext2_write</code> <code>028c_fs_cwd_stat</code></p></blockquote><h2 id="功能概述" tabindex="-1">功能概述 <a class="header-anchor" href="#功能概述" aria-label="Permalink to &quot;功能概述&quot;">​</a></h2><p>ext2 文件系统驱动，挂载 QEMU ext2 分区。支持读取、写入、创建/删除文件和目录、per-process 工作目录和 stat 元数据。数据通过 AHCI SATA DMA 回写磁盘。</p><h2 id="磁盘格式" tabindex="-1">磁盘格式 <a class="header-anchor" href="#磁盘格式" aria-label="Permalink to &quot;磁盘格式&quot;">​</a></h2><h3 id="superblock-kernel-fs-ext2-types-hpp" tabindex="-1">Superblock (<code>kernel/fs/ext2_types.hpp</code>) <a class="header-anchor" href="#superblock-kernel-fs-ext2-types-hpp" aria-label="Permalink to &quot;Superblock (`kernel/fs/ext2_types.hpp`)&quot;">​</a></h3><ul><li><code>s_inodes_count / s_blocks_count / s_log_block_size / s_magic = 0xEF53</code></li><li><code>block_size = 1024 &lt;&lt; s_log_block_size</code></li></ul><h3 id="inode" tabindex="-1">Inode <a class="header-anchor" href="#inode" aria-label="Permalink to &quot;Inode&quot;">​</a></h3><ul><li><code>i_mode / i_uid / i_size / i_block[15]</code></li><li>直接块 0-11，<code>i_block[12]</code> 单重间接块，<code>i_block[13]</code> 双重间接块</li></ul><h3 id="目录项" tabindex="-1">目录项 <a class="header-anchor" href="#目录项" aria-label="Permalink to &quot;目录项&quot;">​</a></h3><ul><li><code>Ext2DirEntry [[gnu::packed]]</code>: <code>inode / rec_len / name_len / file_type / name[]</code></li></ul><h2 id="初始化-ext2-init" tabindex="-1">初始化 (<code>ext2_init()</code>) <a class="header-anchor" href="#初始化-ext2-init" aria-label="Permalink to &quot;初始化 (`ext2_init()`)&quot;">​</a></h2><ol><li>读 superblock (磁盘偏移 1024B)，验证 magic <code>0xEF53</code></li><li>计算 <code>block_size</code></li><li>读 block group descriptor table</li></ol><h2 id="读取操作" tabindex="-1">读取操作 <a class="header-anchor" href="#读取操作" aria-label="Permalink to &quot;读取操作&quot;">​</a></h2><ul><li><code>ext2_read_inode(ino)</code> — group=(ino-1)/inodes_per_group，偏移计算</li><li><code>ext2_read_file(inode, buf, offset, len)</code> — 遍历 <code>i_block[0-11]</code> + <code>i_block[12]</code> 间接块</li><li><code>ext2_readdir(inode, index)</code> — <code>rec_len</code> 步进遍历目录数据块</li></ul><h2 id="写入操作-028b" tabindex="-1">写入操作 (028b) <a class="header-anchor" href="#写入操作-028b" aria-label="Permalink to &quot;写入操作 (028b)&quot;">​</a></h2><ul><li><strong>Block 分配器</strong>: 扫描 block bitmap → 分配并标记 → 回写 bitmap</li><li><strong>Inode 分配器</strong>: 扫描 inode bitmap → 分配并标记 → 回写 bitmap</li><li><code>ext2_file_write()</code> — 按需分配新 block，更新 inode size，回写 inode</li><li><code>ext2_create(parent, name)</code> — 分配 inode + 目录项 + 回写</li><li><code>ext2_mkdir(parent, name)</code> — 分配 inode + 初始化 <code>.</code>/<code>..</code> 目录项</li><li><code>ext2_unlink(parent, name)</code> — 移除目录项 + 释放 block/inode + 回写 bitmap</li></ul><h2 id="工作目录-stat-028c" tabindex="-1">工作目录 &amp; stat (028c) <a class="header-anchor" href="#工作目录-stat-028c" aria-label="Permalink to &quot;工作目录 &amp; stat (028c)&quot;">​</a></h2><ul><li>per-process <code>cwd[256]</code> 字段，初始 <code>&quot;/&quot;</code></li><li>相对路径解析: 结合 cwd 拼接为绝对路径</li><li><code>sys_chdir</code>: 更新 cwd，验证目标路径存在且为目录</li><li><code>sys_getcwd</code>: 返回 cwd 字符串</li><li><code>sys_stat / sys_fstat</code>: 返回 <code>struct stat {st_mode, st_size, st_ino, st_type}</code></li></ul><h2 id="ahci-回写" tabindex="-1">AHCI 回写 <a class="header-anchor" href="#ahci-回写" aria-label="Permalink to &quot;AHCI 回写&quot;">​</a></h2><ul><li>ext2 修改后的 block/bitmap/inode 通过 <code>AHCI::write</code> 回写磁盘</li></ul><h2 id="系统调用" tabindex="-1">系统调用 <a class="header-anchor" href="#系统调用" aria-label="Permalink to &quot;系统调用&quot;">​</a></h2><table tabindex="0"><thead><tr><th>编号</th><th>功能</th></tr></thead><tbody><tr><td><code>SYS_creat</code></td><td>创建文件</td></tr><tr><td><code>SYS_mkdir</code></td><td>创建目录</td></tr><tr><td><code>SYS_unlink</code></td><td>删除文件</td></tr><tr><td><code>SYS_rmdir</code></td><td>删除目录</td></tr><tr><td><code>SYS_chdir</code></td><td>切换工作目录</td></tr><tr><td><code>SYS_getcwd</code></td><td>获取工作目录</td></tr><tr><td><code>SYS_stat</code> / <code>SYS_fstat</code></td><td>获取文件元数据</td></tr></tbody></table><h2 id="源码位置" tabindex="-1">源码位置 <a class="header-anchor" href="#源码位置" aria-label="Permalink to &quot;源码位置&quot;">​</a></h2><ul><li><code>kernel/fs/ext2.hpp/cpp</code> — ext2 驱动</li><li><code>kernel/fs/ext2_types.hpp</code> — ext2 磁盘格式定义</li><li><code>kernel/fs/path.hpp/cpp</code> — 路径解析工具</li><li><code>kernel/fs/stat.hpp</code> — stat 结构体</li></ul>',25)])])}const u=t(i,[["render",c]]);export{p as __pageData,u as default};
